import React, { useState, useCallback, useRef } from 'react';
import { Layout } from './components/Layout';
import { ImageCanvas } from './components/ImageCanvas';
import { GeminiService } from './services/geminiService';
import { ImageState, GenerationStatus } from './types';
import { 
  Upload, 
  UserCircle2, 
  Wand2, 
  ArrowRight, 
  Sparkles, 
  AlertCircle,
  X,
  Type
} from 'lucide-react';

const App: React.FC = () => {
  const [images, setImages] = useState<ImageState>({
    original: null,
    current: null,
    history: []
  });

  const [status, setStatus] = useState<GenerationStatus>({
    loading: false,
    error: null,
    message: ''
  });

  const [prompt, setPrompt] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const result = e.target?.result as string;
        setImages({
          original: result,
          current: result,
          history: []
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const generateFemaleVersion = async () => {
    if (!images.original) return;

    setStatus({ loading: true, error: null, message: 'Analyzing facial features...' });
    try {
      const result = await GeminiService.generateFemaleVersion(images.original);
      setImages(prev => ({
        ...prev,
        current: result,
        history: [prev.current!, ...prev.history]
      }));
      setStatus({ loading: false, error: null, message: 'Transformation complete!' });
    } catch (err: any) {
      console.error(err);
      setStatus({ loading: false, error: err.message || "Failed to generate image", message: '' });
    }
  };

  const handleCustomEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || !images.current) return;

    setStatus({ loading: true, error: null, message: 'Applying magic...' });
    try {
      const result = await GeminiService.editImage(images.current, prompt);
      setImages(prev => ({
        ...prev,
        current: result,
        history: [prev.current!, ...prev.history]
      }));
      setPrompt('');
      setStatus({ loading: false, error: null, message: 'Magic applied!' });
    } catch (err: any) {
      console.error(err);
      setStatus({ loading: false, error: err.message || "Failed to edit image", message: '' });
    }
  };

  const undoLastAction = () => {
    if (images.history.length === 0) return;
    const newHistory = [...images.history];
    const previous = newHistory.shift();
    setImages(prev => ({
      ...prev,
      current: previous || prev.original,
      history: newHistory
    }));
  };

  const reset = () => {
    setImages({ original: null, current: null, history: [] });
    setStatus({ loading: false, error: null, message: '' });
  };

  return (
    <Layout>
      <div className="flex flex-col gap-12 items-center">

        {/* Hero Section */}
        {!images.original && (
          <div className="text-center space-y-6 max-w-2xl animate-in fade-in slide-in-from-bottom-8 duration-1000">
            <h1 className="text-5xl md:text-7xl font-extrabold tracking-tight font-heading leading-tight">
              Reimagine <br /> 
              <span className="gradient-text">Every Persona</span>
            </h1>
            <p className="text-white/60 text-lg md:text-xl font-light leading-relaxed">
              Upload a photo and instantly generate its female counterpart or use natural language to edit textures, backgrounds, and styles.
            </p>

            <div className="pt-8">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="group relative px-8 py-4 bg-white text-black font-bold rounded-2xl hover:bg-white/90 transition-all flex items-center gap-3 mx-auto shadow-2xl shadow-white/10"
              >
                <Upload className="w-5 h-5 group-hover:scale-110 transition-transform" />
                Start with a Photo
                <input 
                  type="file" 
                  hidden 
                  ref={fileInputRef} 
                  accept="image/*" 
                  onChange={handleFileUpload} 
                />
              </button>
              <p className="mt-4 text-white/30 text-xs">PNG, JPG or WebP supported up to 10MB</p>
            </div>
          </div>
        )}

        {/* Editor Interface */}
        {images.original && (
          <div className="w-full grid grid-cols-1 lg:grid-cols-12 gap-8 items-start animate-in fade-in slide-in-from-bottom-4 duration-700">

            {/* Left Column: Canvas */}
            <div className="lg:col-span-7 xl:col-span-8 flex flex-col gap-4">
              <div className="flex items-center justify-between px-2">
                <div className="flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                  <span className="text-xs font-bold uppercase tracking-widest text-white/40">Studio View</span>
                </div>
                <button 
                  onClick={reset}
                  className="text-xs font-medium text-white/40 hover:text-white flex items-center gap-1 transition-colors"
                >
                  <X size={14} /> New Session
                </button>
              </div>

              <ImageCanvas 
                imageUrl={images.current!} 
                originalUrl={images.original}
                isGenerating={status.loading}
                onUndo={images.history.length > 0 ? undoLastAction : undefined}
              />
            </div>

            {/* Right Column: Controls */}
            <div className="lg:col-span-5 xl:col-span-4 flex flex-col gap-6">

              {/* Primary Action: Female Version */}
              <div className="glass rounded-3xl p-6 border-white/10 glow-purple">
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-8 h-8 bg-purple-500/20 rounded-lg flex items-center justify-center">
                    <UserCircle2 className="text-purple-400 w-5 h-5" />
                  </div>
                  <h3 className="font-bold text-white/90">Identity Shift</h3>
                </div>

                <p className="text-sm text-white/50 mb-6 leading-relaxed">
                  Transform this person into their female equivalent while preserving structural features and skin tone.
                </p>

                <button 
                  disabled={status.loading}
                  onClick={generateFemaleVersion}
                  className="w-full py-4 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 disabled:opacity-50 disabled:cursor-not-allowed rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-900/40"
                >
                  {status.loading ? (
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  ) : (
                    <Sparkles className="w-5 h-5" />
                  )}
                  Generate Female Version
                </button>
              </div>

              {/* Secondary Action: AI Prompt Edit */}
              <div className="glass rounded-3xl p-6 border-white/10">
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-8 h-8 bg-blue-500/20 rounded-lg flex items-center justify-center">
                    <Wand2 className="text-blue-400 w-5 h-5" />
                  </div>
                  <h3 className="font-bold text-white/90">AI Instruction</h3>
                </div>

                <form onSubmit={handleCustomEdit} className="space-y-4">
                  <div className="relative">
                    <textarea 
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                      placeholder="e.g. 'Add a retro film grain', 'Make it look like a oil painting', 'Change the background to a neon city'"
                      className="w-full h-32 bg-white/5 border border-white/10 rounded-xl p-4 text-sm focus:outline-none focus:border-purple-500/50 resize-none placeholder:text-white/20"
                    />
                    <div className="absolute bottom-3 right-3 text-[10px] text-white/20 font-mono">
                      Gemini 2.5 Flash
                    </div>
                  </div>

                  <button 
                    type="submit"
                    disabled={status.loading || !prompt.trim()}
                    className="w-full py-3 bg-white/10 hover:bg-white/20 disabled:opacity-30 rounded-xl font-semibold text-sm flex items-center justify-center gap-2 transition-all"
                  >
                    Run Instruction
                    <ArrowRight className="w-4 h-4" />
                  </button>
                </form>
              </div>

              {/* Status & Messages */}
              {status.error && (
                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl flex gap-3 items-start animate-in fade-in slide-in-from-top-2">
                  <AlertCircle className="text-red-400 w-5 h-5 shrink-0 mt-0.5" />
                  <div className="text-xs text-red-200/80 leading-relaxed">
                    <span className="font-bold text-red-400 block mb-1">Processing Error</span>
                    {status.error}
                  </div>
                </div>
              )}

              {status.message && !status.error && (
                <div className="text-center">
                  <p className="text-xs font-medium text-white/30 tracking-wider uppercase">
                    {status.message}
                  </p>
                </div>
              )}

            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;
